@Test
public void multipleListeners() throws Exception {
    InvocationListener listener1 = mock(InvocationListener.class);
    InvocationListener listener2 = mock(InvocationListener.class);

    List mockedList = mock(List.class, withSettings().invocationListeners(listener1, listener2));
    reset(mockedList);

    mockedList.add("test");

    verify(listener1).reportInvocation(any(MethodInvocationReport.class));
    verify(listener2).reportInvocation(any(MethodInvocationReport.class));
}

@Test
public void customAnswerPreservedAfterReset() throws Exception {
    Answer<String> customAnswer = new Answer<String>() {
        public String answer(InvocationOnMock invocation) {
            return "custom";
        }
    };

    List mockedList = mock(List.class, withSettings().defaultAnswer(customAnswer));
    when(mockedList.get(0)).thenReturn("original");
    reset(mockedList);

    assertEquals("custom", mockedList.get(0));
}

@Test
public void serializableSettingPreservedAfterReset() throws Exception {
    List mockedList = mock(List.class, withSettings().serializable());
    reset(mockedList);

    assertTrue(mockedList instanceof java.io.Serializable);
}
